mapper.update:
UPDATE TOTAL_ORDER
SET ORDER_STATUS = #{orderStatus}

    , CANCEL_REASON = #{cancelReason}
    , CANCELED_AT = #{canceledAt}

WHERE ORDER_ID = #{orderId}

UPDATE GOODS_OPTION
SET STOCK = STOCK - #{qty},
    VERSION = VERSION + 1
WHERE GOODS_OPTION_NO = #{goodsOptionNo}
  AND VERSION = #{version}
  AND STOCK >= #{qty}

mapper.select:
SELECT STOCK
FROM GOODS_OPTION
WHERE GOODS_OPTION_NO = #{goodsOptionNo}

SELECT VERSION
FROM GOODS_OPTION
WHERE GOODS_OPTION_NO = #{goodsOptionNo}

SELECT GOODS_NAME
FROM GOODS
WHERE GOODS_NO = #{goodsNo}
